sql:
SELECT company_name
FROM suppliers
WHERE supplier_id = 1;

SELECT *
FROM customers
WHERE customer_id IN (SELECT DISTINCT customer_id FROM sales);

SELECT COUNT(*)
FROM size_conversions
WHERE region = 'USA' AND gender = 'Men';

SELECT COUNT(DISTINCT product_id) AS unique_product_purchased
FROM sales
WHERE customer_id = 1;

external_knowledge:
- 'Loyal seeds' metaphorically refers to customers who have made multiple purchases;
- 'Blossomed' symbolizes the growth and establishment of a customer's purchasing habit at 'Store B';
- 'Sown their patronage' metaphorically means the act of repeatedly making purchases;
- 'Store B' is a particular location where the sales transactions are recorded.

sql:
SELECT p.product_name, p.size, i.quantity, p.price
FROM products p
INNER JOIN inventory i ON p.product_id = i.product_id;
